using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public sealed class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public sealed class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public sealed class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

public sealed class TicketPredictionResponse
{
    public required string PredictedCategory { get; set; }
    public required Dictionary<string, float> Confidence { get; set; }
}

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class TicketModelService
{
    private readonly MLContext _mlContext = new(seed: 0);
    private readonly string _modelPath;
    private readonly string _dataPath;
    private ITransformer? _model;
    private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
    private string[]? _categoryLabels;

    public TicketModelService(IWebHostEnvironment env)
    {
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "ticket_model.zip");
    }

    public MulticlassClassificationMetrics TrainAndEvaluate()
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(split.TrainSet);

        var predictions = _model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        _mlContext.Model.Save(_model, dataView.Schema, _modelPath);

        // Cache category labels from the label column key-type metadata
        var labelCol = dataView.Schema["Category"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();

        // Re-fit on full data to extract labels from the key mapping
        var fullModel = pipeline.Fit(dataView);
        var transformedSchema = fullModel.Transform(dataView).Schema;
        var labelKeyCol = transformedSchema["Label"];
        labelKeyCol.GetKeyValues(ref slotNames);
        _categoryLabels = slotNames.DenseValues()
            .Select(v => v.ToString()).ToArray();

        // Save the full-data model as the production model
        _model = fullModel;
        _mlContext.Model.Save(_model, dataView.Schema, _modelPath);
        _predictionEngine = _mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        return metrics;
    }

    public TicketPredictionResponse Predict(TicketRequest request)
    {
        EnsureModel();

        var prediction = _predictionEngine!.Predict(new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        });

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < _categoryLabels!.Length; i++)
        {
            confidence[_categoryLabels[i]] = prediction.Score[i];
        }

        return new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        };
    }

    private void EnsureModel()
    {
        if (_predictionEngine is not null)
            return;

        if (!File.Exists(_modelPath))
            throw new InvalidOperationException(
                "Model not trained yet. POST to /api/tickets/train first.");

        _model = _mlContext.Model.Load(_modelPath, out var schema);
        _predictionEngine = _mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Recover category labels from the saved model
        var dummyData = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
        var transformed = _model.Transform(dummyData);
        var labelCol = transformed.Schema["Label"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        labelCol.GetKeyValues(ref slotNames);
        _categoryLabels = slotNames.DenseValues()
            .Select(v => v.ToString()).ToArray();
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.ML.Data;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public sealed class TicketsController(TicketModelService modelService) : ControllerBase
{
    /// <summary>
    /// Trains the model on the CSV data and returns evaluation metrics.
    /// </summary>
    [HttpPost("train")]
    public IActionResult Train()
    {
        var metrics = modelService.TrainAndEvaluate();

        return Ok(new
        {
            Message = "Model trained successfully",
            Metrics = FormatMetrics(metrics)
        });
    }

    /// <summary>
    /// Predicts the category for a support ticket.
    /// </summary>
    [HttpPost("predict")]
    public IActionResult Predict([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) ||
            string.IsNullOrWhiteSpace(request.Description))
        {
            return BadRequest("Subject and Description are required.");
        }

        if (request.Priority is < 1 or > 3)
        {
            return BadRequest("Priority must be between 1 and 3.");
        }

        var result = modelService.Predict(request);
        return Ok(result);
    }

    private static object FormatMetrics(MulticlassClassificationMetrics m) => new
    {
        m.MacroAccuracy,
        m.MicroAccuracy,
        m.LogLoss,
        m.LogLossReduction,
        PerClassLogLoss = m.PerClassLogLoss.ToArray()
    };
}

